// --- Chrome profile discovery ---
// chromeDataDir returns the Chrome user data directory for the current OS.
func chromeDataDir() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}

	switch runtime.GOOS {
	case "darwin":
		return filepath.Join(home, "Library", "Application Support", "Google", "Chrome"), nil
	case "linux":
		return filepath.Join(home, ".config", "google-chrome"), nil
	case "windows":
		localAppData := os.Getenv("LOCALAPPDATA")
		if localAppData == "" {
			localAppData = filepath.Join(home, "AppData", "Local")
		}
		return filepath.Join(localAppData, "Google", "Chrome", "User Data"), nil
	default:
		return "", fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
}

// discoverChromeProfiles finds Chrome profiles and counts cookies matching the domain.
func discoverChromeProfiles(domain string, requiredCookies []string) ([]chromeProfile, error) {
	dataDir, err := chromeDataDir()
	if err != nil {
		return nil, err
	}

	entries, err := os.ReadDir(dataDir)
	if err != nil {
		return nil, fmt.Errorf("cannot read Chrome data directory: %w", err)
	}

	// Match domain for SQLite query — host_key uses leading dot (e.g. ".notion.so")
	domainPattern := "%" + strings.TrimPrefix(domain, ".") + "%"

	var profiles []chromeProfile
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		name := entry.Name()
		if name != "Default" && !strings.HasPrefix(name, "Profile ") {
			continue
		}

		profilePath := filepath.Join(dataDir, name)
		cookiesDB := filepath.Join(profilePath, "Cookies")
		if _, err := os.Stat(cookiesDB); err != nil {
			continue
		}

		displayName := readProfileDisplayName(filepath.Join(profilePath, "Preferences"))
		if displayName == "" {
			displayName = name
		}

		inspection := inspectCookiesForDomain(cookiesDB, domainPattern, requiredCookies)

		profiles = append(profiles, chromeProfile{
			Dir:                 name,
			DisplayName:         displayName,
			CookieCount:         inspection.Count,
			RequiredCookieCount: inspection.RequiredCookieCount,
			MissingCookies:      inspection.MissingCookies,
		})
	}

	// Sort: profiles with required auth cookies first, then with the most
	// target-domain cookies, then by directory name for determinism.
	sort.Slice(profiles, func(i, j int) bool {
		if profiles[i].RequiredCookieCount != profiles[j].RequiredCookieCount {
			return profiles[i].RequiredCookieCount > profiles[j].RequiredCookieCount
		}
		if profiles[i].CookieCount != profiles[j].CookieCount {
			return profiles[i].CookieCount > profiles[j].CookieCount
		}
		return profiles[i].Dir < profiles[j].Dir
	})

	return profiles, nil
}

// readProfileDisplayName extracts the human-readable name from Chrome's Preferences JSON.
func readProfileDisplayName(prefsPath string) string {
	data, err := os.ReadFile(prefsPath)
	if err != nil {
		return ""
	}
	var prefs struct {
		Profile struct {
			Name string `json:"name"`
		} `json:"profile"`
	}
	if err := json.Unmarshal(data, &prefs); err != nil {
		return ""
	}
	return prefs.Profile.Name
}

type chromeCookieInspection struct {
	Count               int
	RequiredCookieCount int
	MissingCookies      []string
}

func inspectCookiesForDomain(cookiesDB, domainPattern string, requiredCookies []string) chromeCookieInspection {
	result := chromeCookieInspection{Count: countCookiesForDomain(cookiesDB, domainPattern)}
	if len(requiredCookies) == 0 {
		return result
	}

	missing := make(map[string]bool, len(requiredCookies))
	for _, name := range requiredCookies {
		missing[name] = true
	}

	tmpFile, err := os.CreateTemp("", "cookies-probe-*.db")
	if err != nil {
		result.MissingCookies = requiredCookies
		return result
	}
	tmpPath := tmpFile.Name()
	tmpFile.Close()
	defer os.Remove(tmpPath)
	defer os.Remove(tmpPath + "-wal")
	defer os.Remove(tmpPath + "-shm")

	if err := copyFileIfExists(cookiesDB, tmpPath); err != nil {
		result.MissingCookies = requiredCookies
		return result
	}
	_ = copyFileIfExists(cookiesDB+"-wal", tmpPath+"-wal")
	_ = copyFileIfExists(cookiesDB+"-shm", tmpPath+"-shm")

	db, err := sql.Open("sqlite", "file:"+tmpPath+"?mode=ro&_journal_mode=OFF&_busy_timeout=2000")
	if err != nil {
		result.MissingCookies = requiredCookies
		return result
	}
	defer db.Close()

	placeholders := make([]string, 0, len(requiredCookies))
	args := make([]any, 0, len(requiredCookies)+1)
	args = append(args, domainPattern)
	for _, name := range requiredCookies {
		placeholders = append(placeholders, "?")
		args = append(args, name)
	}
	query := "SELECT DISTINCT name FROM cookies WHERE host_key LIKE ? AND name IN (" + strings.Join(placeholders, ",") + ")"
	rows, err := db.Query(query, args...)
	if err != nil {
		result.MissingCookies = requiredCookies
		return result
	}
	defer rows.Close()

	for rows.Next() {
		var name string
		if err := rows.Scan(&name); err != nil {
			continue
		}
		if missing[name] {
			delete(missing, name)
			result.RequiredCookieCount++
		}
	}
	for _, name := range requiredCookies {
		if missing[name] {
			result.MissingCookies = append(result.MissingCookies, name)
		}
	}
	return result
}

// countCookiesForDomain copies the Cookies DB (plus WAL/SHM) to temp and counts matching rows.
// Uses sqlite3 when available; host_key is plaintext so no decryption is needed.
func countCookiesForDomain(cookiesDB, domainPattern string) int {
	tmpFile, err := os.CreateTemp("", "cookies-probe-*.db")
	if err != nil {
		return 0
	}
	tmpPath := tmpFile.Name()
	tmpFile.Close()
	defer os.Remove(tmpPath)
	defer os.Remove(tmpPath + "-wal")
	defer os.Remove(tmpPath + "-shm")

	// Copy the database file plus WAL/SHM to avoid Chrome's WAL lock
	// and to include uncommitted cookie writes that are still in the WAL.
	if err := copyFileIfExists(cookiesDB, tmpPath); err != nil {
		return 0
	}
	_ = copyFileIfExists(cookiesDB+"-wal", tmpPath+"-wal")
	_ = copyFileIfExists(cookiesDB+"-shm", tmpPath+"-shm")

	db, err := sql.Open("sqlite", tmpPath)
	if err != nil {
		return 0
	}
	defer db.Close()

	count := 0
	if err := db.QueryRow(`SELECT COUNT(*) FROM cookies WHERE host_key LIKE ?`, domainPattern).Scan(&count); err != nil {
		return 0
	}
	return count
}

// copyFileIfExists copies src to dst. Returns nil if src does not exist.
func copyFileIfExists(src, dst string) error {
	in, err := os.Open(src)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	defer in.Close()
	out, err := os.Create(dst)
	if err != nil {
		return err
	}
	defer out.Close()
	_, err = io.Copy(out, in)
	return err
}

// resolveChromeProfile determines which Chrome profile to read cookies from.
// Priority: --profile flag > auto-detect (single match) > interactive prompt.
func resolveChromeProfile(w io.Writer, r io.Reader, domain, profileFlag string, requiredCookies []string) (string, error) {
	if profileFlag != "" {
		return resolveProfileByName(profileFlag)
	}

	profiles, err := discoverChromeProfiles(domain, requiredCookies)
	if err != nil {
		// Profile probing is optional; cookie extraction can still succeed without it.
		fmt.Fprintf(w, "Could not inspect Chrome profiles (%v); continuing without auto-detection.\n", err)
		return "", nil
	}

	// Prefer profiles that contain every required auth cookie. If the CLI does
	// not know specific cookie names, fall back to any target-domain cookie.
	var withRequired []chromeProfile
	var withCookies []chromeProfile
	for _, p := range profiles {
		if len(requiredCookies) > 0 && p.RequiredCookieCount == len(requiredCookies) {
			withRequired = append(withRequired, p)
		}
		if p.CookieCount > 0 {
			withCookies = append(withCookies, p)
		}
	}

	if len(withRequired) > 0 {
		return chooseChromeProfile(w, r, withRequired, domain, true)
	}
	if len(requiredCookies) > 0 {
		printMissingCookieHint(w, profiles, requiredCookies)
	}
	if len(withCookies) > 0 {
		return chooseChromeProfile(w, r, withCookies, domain, false)
	}
	return "", fmt.Errorf("no Chrome profile has cookies for %s", domain)
}

func printMissingCookieHint(w io.Writer, profiles []chromeProfile, requiredCookies []string) {
	if len(requiredCookies) == 0 {
		return
	}
	for _, p := range profiles {
		if p.CookieCount == 0 || len(p.MissingCookies) == 0 {
			continue
		}
		fmt.Fprintf(w, "Chrome profile %s (%s) is missing required cookies: %s\n", p.DisplayName, p.Dir, strings.Join(p.MissingCookies, ", "))
		return
	}
}

func chooseChromeProfile(w io.Writer, r io.Reader, profiles []chromeProfile, domain string, required bool) (string, error) {
	label := "cookies"
	if required {
		label = "required cookies"
	}

	switch len(profiles) {
	case 1:
		fmt.Fprintf(w, "Auto-detected Chrome profile: %s (%s, %d %s)\n", profiles[0].DisplayName, profiles[0].Dir, profileCookieCount(profiles[0], required), label)
		return profiles[0].Dir, nil
	default:
		// Multiple profiles have matching cookies. Non-interactive runs pick the
		// strongest match; terminals get an explicit choice.
		if !isTerminal(w) {
			selected := profiles[0]
			fmt.Fprintf(w, "Auto-selected Chrome profile: %s (%s, %d %s)\n", selected.DisplayName, selected.Dir, profileCookieCount(selected, required), label)
			fmt.Fprintf(w, "Use --profile to select a different profile.\n")
			return selected.Dir, nil
		}

		fmt.Fprintf(w, "Multiple Chrome profiles have cookies for %s:\n", domain)
		for i, p := range profiles {
			fmt.Fprintf(w, "  %d. %s (%s, %d %s)\n", i+1, p.DisplayName, p.Dir, profileCookieCount(p, required), label)
		}
		fmt.Fprintf(w, "Which profile? [1]: ")

		scanner := bufio.NewScanner(r)
		choice := 1
		if scanner.Scan() {
			text := strings.TrimSpace(scanner.Text())
			if text != "" {
				fmt.Sscanf(text, "%d", &choice)
			}
		}
		if choice < 1 || choice > len(profiles) {
			choice = 1
		}
		selected := profiles[choice-1]
		fmt.Fprintf(w, "Using profile: %s (%s)\n", selected.DisplayName, selected.Dir)
		return selected.Dir, nil
	}
}

func profileCookieCount(profile chromeProfile, required bool) int {
	if required {
		return profile.RequiredCookieCount
	}
	return profile.CookieCount
}

// resolveProfileByName finds a Chrome profile directory by its display name.
func resolveProfileByName(name string) (string, error) {
	dataDir, err := chromeDataDir()
	if err != nil {
		return "", err
	}

	entries, err := os.ReadDir(dataDir)
	if err != nil {
		return "", err
	}

	lowerName := strings.ToLower(name)
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dirName := entry.Name()
		if dirName != "Default" && !strings.HasPrefix(dirName, "Profile ") {
			continue
		}
		displayName := readProfileDisplayName(filepath.Join(dataDir, dirName, "Preferences"))
		if strings.ToLower(displayName) == lowerName || strings.ToLower(dirName) == lowerName {
			return dirName, nil
		}
	}

	return "", fmt.Errorf("Chrome profile %q not found", name)
}

// --- Cookie extraction tools ---

var detectedPycookiecheatCLIPath string

func runCookieToolProbe(name string, args ...string) error {
	cmd := exec.Command(name, args...)
	cmd.Stdout = io.Discard
	cmd.Stderr = io.Discard
	return cmd.Run()
}

// detectCookieTool checks for available cookie extraction tools in preference order.
func detectCookieTool() (string, error) {
	detectedPycookiecheatCLIPath = ""
	tools := []struct {
		name  string
		check []string
	}{
		{"pycookiecheat", []string{"python3", "-c", "import pycookiecheat"}},
		{"pycookiecheat-cli", []string{"pycookiecheat", "--help"}},
		{"cookies", []string{"cookies", "--help"}},
		{"cookie-scoop", []string{"cookie-scoop", "--help"}},
	}

	for _, tool := range tools {
		if runtime.GOOS == "windows" && (tool.name == "pycookiecheat" || tool.name == "pycookiecheat-cli") {
			continue
		}
		if err := runCookieToolProbe(tool.check[0], tool.check[1:]...); err == nil {
			if tool.name == "pycookiecheat-cli" {
				detectedPycookiecheatCLIPath = tool.check[0]
				if path, err := exec.LookPath(tool.check[0]); err == nil {
					detectedPycookiecheatCLIPath = path
				}
			}
			return tool.name, nil
		}
	}
	if runtime.GOOS == "windows" {
		return "", fmt.Errorf("no cookie extraction tool found; pycookiecheat does not support Windows. Use `auth login --browser` (live Chrome via CDP) or install cookie-scoop-cli")
	}
	return "", fmt.Errorf("no cookie extraction tool found; install one: pip install pycookiecheat")
}

// extractCookies shells out to the detected tool and returns a Cookie header value string.
// profileDir selects which Chrome profile to read from (e.g. "Default", "Profile 1").
func extractCookies(tool, domain, profileDir string) (string, error) {
	switch tool {
	case "pycookiecheat":
		return extractViaPycookiecheat(domain, profileDir)
	case "pycookiecheat-cli":
		return extractViaPycookiecheatCLI(domain, profileDir)
	case "cookies":
		return extractViaCookiesCLI(domain)
	case "cookie-scoop":
		return extractViaCookieScoop(domain, profileDir)
	default:
		return "", fmt.Errorf("unknown cookie tool: %s", tool)
	}
}

func extractViaPycookiecheat(domain, profileDir string) (string, error) {
	cleanDomain := strings.TrimPrefix(domain, ".")
	cookiePath := ""
	if profileDir != "" {
		dataDir, err := chromeDataDir()
		if err == nil {
			cookiePath = filepath.Join(dataDir, profileDir, "Cookies")
		}
	}

	var script string
	if cookiePath != "" {
		// Use forward slashes so Python doesn't interpret backslashes as escapes on Windows
		safePath := filepath.ToSlash(cookiePath)
		script = fmt.Sprintf(
			`import json; from pycookiecheat import chrome_cookies; print(json.dumps(chrome_cookies("https://%s", cookie_file="%s")))`,
			cleanDomain, safePath,
		)
	} else {
		script = fmt.Sprintf(
			`import json; from pycookiecheat import chrome_cookies; print(json.dumps(chrome_cookies("https://%s")))`,
			cleanDomain,
		)
	}

	var out bytes.Buffer
	cmd := exec.Command("python3", "-c", script)
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("pycookiecheat failed: %w", err)
	}

	var cookies map[string]string
	if err := json.Unmarshal(out.Bytes(), &cookies); err != nil {
		return "", fmt.Errorf("parsing pycookiecheat output: %w", err)
	}

	var parts []string
	for name, value := range cookies {
		parts = append(parts, name+"="+value)
	}
	return strings.Join(parts, "; "), nil
}

func extractViaPycookiecheatCLI(domain, profileDir string) (string, error) {
	cleanDomain := strings.TrimPrefix(domain, ".")
	var args []string
	if profileDir != "" {
		dataDir, err := chromeDataDir()
		if err != nil {
			return "", err
		}
		args = append(args, "-c", filepath.Join(dataDir, profileDir, "Cookies"))
	}
	args = append(args, "https://"+cleanDomain)

	pycookiecheatBin := detectedPycookiecheatCLIPath
	if pycookiecheatBin == "" {
		pycookiecheatBin = "pycookiecheat"
	}

	var out bytes.Buffer
	cmd := exec.Command(pycookiecheatBin, args...)
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("pycookiecheat cli failed: %w", err)
	}

	var cookies map[string]string
	if err := json.Unmarshal(out.Bytes(), &cookies); err != nil {
		return "", fmt.Errorf("parsing pycookiecheat output: %w", err)
	}

	var parts []string
	for name, value := range cookies {
		parts = append(parts, name+"="+value)
	}
	return strings.Join(parts, "; "), nil
}

func extractViaCookiesCLI(domain string) (string, error) {
	// barnardb/cookies doesn't support profile selection — reads Default
	var out bytes.Buffer
	cmd := exec.Command("cookies", "https://"+strings.TrimPrefix(domain, "."))
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("cookies cli failed: %w", err)
	}

	result := strings.TrimSpace(out.String())
	result = strings.TrimPrefix(result, "Cookie: ")
	return result, nil
}

// parseCookieString splits a "name1=value1; name2=value2" string into a map.
func parseCookieString(cookies string) map[string]string {
	m := make(map[string]string)
	for _, pair := range strings.Split(cookies, "; ") {
		pair = strings.TrimSpace(pair)
		if pair == "" {
			continue
		}
		idx := strings.IndexByte(pair, '=')
		if idx < 0 {
			continue
		}
		m[pair[:idx]] = pair[idx+1:]
	}
	return m
}

func extractViaCookieScoop(domain, profileDir string) (string, error) {
	cleanDomain := strings.TrimPrefix(domain, ".")
	args := []string{"--url", "https://" + cleanDomain, "--header"}
	if profileDir != "" {
		args = append(args, "--chrome-profile", profileDir)
	}

	var out bytes.Buffer
	cmd := exec.Command("cookie-scoop", args...)
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("cookie-scoop failed: %w", err)
	}

	result := strings.TrimSpace(out.String())
	result = strings.TrimPrefix(result, "Cookie: ")
	return result, nil
}

type browserSessionProof struct {
	APIName               string `json:"api_name"`
	CookieDomain          string `json:"cookie_domain"`
	ValidationMethod      string `json:"validation_method"`
	ValidationPath        string `json:"validation_path"`
	StatusCode            int    `json:"status_code"`
	AuthSource            string `json:"auth_source"`
	CredentialFingerprint string `json:"credential_fingerprint"`
	VerifiedAt            string `json:"verified_at"`
}

func browserSessionProofPath(cfg *config.Config) string {
	if cfg == nil || cfg.Path == "" {
		home, _ := os.UserHomeDir()
		return filepath.Join(home, ".config", "facebook-marketplace-pp-cli", "browser-session-proof.json")
	}
	return filepath.Join(filepath.Dir(cfg.Path), "browser-session-proof.json")
}

func clearBrowserSessionProof(cfg *config.Config) error {
	proofPath := browserSessionProofPath(cfg)
	if err := os.Remove(proofPath); err != nil && !errors.Is(err, os.ErrNotExist) {
		return err
	}
	return nil
}

func writeBrowserSessionProof(cfg *config.Config, data []byte) error {
	proofPath := browserSessionProofPath(cfg)
	if err := os.MkdirAll(filepath.Dir(proofPath), 0o700); err != nil {
		return fmt.Errorf("creating proof directory: %w", err)
	}
	tmpPath := proofPath + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
		return fmt.Errorf("writing temporary proof: %w", err)
	}
	if err := os.Rename(tmpPath, proofPath); err != nil {
		_ = os.Remove(tmpPath)
		return fmt.Errorf("publishing proof: %w", err)
	}
	return nil
}

func browserSessionProofStatusForAuth(cfg *config.Config, authHeader string) (bool, string) {
	if cfg == nil {
		return false, "config unavailable"
	}
	if authHeader == "" {
		return false, "no browser session credentials configured"
	}
	data, err := os.ReadFile(browserSessionProofPath(cfg))
	if err != nil {
		return false, "proof not found; run facebook-marketplace-pp-cli auth login --chrome"
	}
	var proof browserSessionProof
	if err := json.Unmarshal(data, &proof); err != nil {
		return false, "proof is not valid JSON; re-run facebook-marketplace-pp-cli auth login --chrome"
	}
	if proof.APIName != "facebook-marketplace" || proof.CookieDomain != ".facebook.com" || proof.ValidationPath != "/marketplace/" {
		return false, "proof does not match this CLI"
	}
	if authHeader != "" && proof.CredentialFingerprint != fingerprintCredential(authHeader) {
		return false, "proof does not match the currently configured browser session"
	}
	if proof.StatusCode < 200 || proof.StatusCode >= 300 {
		return false, fmt.Sprintf("proof recorded HTTP %d", proof.StatusCode)
	}
	return true, fmt.Sprintf("%s %s verified at %s", proof.ValidationMethod, proof.ValidationPath, proof.VerifiedAt)
}

func validateAndWriteBrowserSessionProof(cfg *config.Config, flags *rootFlags) error {
	validationPath := strings.TrimSpace("/marketplace/")
	if validationPath == "" {
		return fmt.Errorf("no browser-session validation endpoint configured in this CLI")
	}
	method := strings.ToUpper(strings.TrimSpace("GET"))
	if method == "" {
		method = "GET"
	}
	if method != "GET" {
		return fmt.Errorf("browser-session validation only supports GET endpoints for now (got %s)", method)
	}

	authHeader := cfg.AuthHeader()
	if authHeader == "" {
		return fmt.Errorf("no browser session credentials were saved")
	}

	c := client.New(cfg, flags.timeout, flags.rateLimit)
	c.NoCache = true
	status, err := c.ProbeGet(validationPath)
	if err != nil {
		return err
	}
	if status < 200 || status >= 300 {
		return fmt.Errorf("validation endpoint returned HTTP %d", status)
	}

	proof := browserSessionProof{
		APIName:               "facebook-marketplace",
		CookieDomain:          ".facebook.com",
		ValidationMethod:      method,
		ValidationPath:        validationPath,
		StatusCode:            status,
		AuthSource:            browserSessionAuthSource(cfg, authHeader),
		CredentialFingerprint: fingerprintCredential(authHeader),
		VerifiedAt:            time.Now().UTC().Format(time.RFC3339),
	}

	data, err := json.MarshalIndent(proof, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling proof: %w", err)
	}
	data = append(data, '\n')
	return writeBrowserSessionProof(cfg, data)
}

func validateAndWriteBrowserSessionProofWithRetry(cfg *config.Config, flags *rootFlags, timeout time.Duration) error {
	deadline := time.Now().Add(timeout)
	var lastErr error
	for {
		if err := validateAndWriteBrowserSessionProof(cfg, flags); err != nil {
			lastErr = err
		} else {
			return nil
		}
		if time.Now().After(deadline) {
			return lastErr
		}
		time.Sleep(time.Second)
	}
}

func fingerprintCredential(value string) string {
	sum := sha256.Sum256([]byte(value))
	return hex.EncodeToString(sum[:8])
}

func browserSessionAuthSource(cfg *config.Config, authHeader string) string {
	if authHeader == "" {
		return "browser"
	}
	if cfg != nil && cfg.AuthSource != "" {
		return cfg.AuthSource
	}
	return "browser"
}

// --- Live browser cookie extraction (session cookies fallback) ---

// extractLiveCookies reads document.cookie from a live Chrome session.
// Tries: agent-browser → browser-use → raw CDP, in that order.
func extractLiveCookies(domain string) (string, error) {
	targetURL := "https://" + strings.TrimPrefix(domain, ".")

	// 1. Try browser-use --connect (preferred — has full DOM/cookie access)
	if _, err := exec.LookPath("browser-use"); err == nil {
		cookies, err := extractViaBrowserUse(targetURL)
		if err == nil && cookies != "" {
			return cookies, nil
		}
	}

	// 2. Try agent-browser --auto-connect (fallback — limited eval in auto-connect mode)
	if _, err := exec.LookPath("agent-browser"); err == nil {
		cookies, err := extractViaAgentBrowser(targetURL)
		if err == nil && cookies != "" {
			return cookies, nil
		}
	}

	// 3. Try raw CDP on common debug ports
	for _, port := range []string{"9222", "9229"} {
		cookies, err := extractViaCDP(targetURL, port)
		if err == nil && cookies != "" {
			return cookies, nil
		}
	}

	return "", fmt.Errorf("no live browser connection available (tried agent-browser, browser-use, CDP)")
}

func extractViaAgentBrowser(targetURL string) (string, error) {
	// Open the target URL (attaches to running Chrome)
	openCmd := exec.Command("agent-browser", "--auto-connect", "open", targetURL)
	openCmd.Stderr = os.Stderr
	if err := openCmd.Run(); err != nil {
		return "", fmt.Errorf("agent-browser open: %w", err)
	}

	// Read document.cookie via eval
	var out bytes.Buffer
	evalCmd := exec.Command("agent-browser", "eval", "document.cookie")
	evalCmd.Stdout = &out
	evalCmd.Stderr = os.Stderr
	if err := evalCmd.Run(); err != nil {
		closeCmd := exec.Command("agent-browser", "close")
		_ = closeCmd.Run()
		return "", fmt.Errorf("agent-browser eval: %w", err)
	}

	// Close the daemon
	closeCmd := exec.Command("agent-browser", "close")
	_ = closeCmd.Run()

	return strings.TrimSpace(out.String()), nil
}

func extractViaBrowserUse(targetURL string) (string, error) {
	// Try connecting to running Chrome
	openCmd := exec.Command("browser-use", "--connect", "open", targetURL)
	openCmd.Stderr = os.Stderr
	if err := openCmd.Run(); err != nil {
		return "", fmt.Errorf("browser-use open: %w", err)
	}

	var out bytes.Buffer
	evalCmd := exec.Command("browser-use", "eval", "document.cookie")
	evalCmd.Stdout = &out
	evalCmd.Stderr = os.Stderr
	if err := evalCmd.Run(); err != nil {
		closeCmd := exec.Command("browser-use", "close")
		_ = closeCmd.Run()
		return "", fmt.Errorf("browser-use eval: %w", err)
	}

	closeCmd := exec.Command("browser-use", "close")
	_ = closeCmd.Run()

	result := strings.TrimSpace(out.String())
	// browser-use eval prefixes with "result: "
	result = strings.TrimPrefix(result, "result: ")
	return result, nil
}

func extractViaCDP(targetURL, port string) (string, error) {
	// Discover available tabs via CDP JSON endpoint
	listURL := fmt.Sprintf("http://localhost:%s/json", port)
	client := &http.Client{Timeout: 2 * time.Second}
	resp, err := client.Get(listURL)
	if err != nil {
		return "", fmt.Errorf("CDP not available on port %s", port)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", err
	}

	// Find a tab matching the target domain
	domain := strings.TrimPrefix(strings.TrimPrefix(targetURL, "https://"), "http://")
	var tabs []struct {
		URL                  string `json:"url"`
		WebSocketDebuggerURL string `json:"webSocketDebuggerUrl"`
	}
	if err := json.Unmarshal(body, &tabs); err != nil {
		return "", fmt.Errorf("parsing CDP tabs: %w", err)
	}

	var wsURL string
	for _, tab := range tabs {
		if strings.Contains(tab.URL, domain) {
			wsURL = tab.WebSocketDebuggerURL
			break
		}
	}
	if wsURL == "" {
		return "", fmt.Errorf("no Chrome tab found for %s", domain)
	}

	// wsURL found but we need a WebSocket client to evaluate JS.
	// For now, report that the tab exists — a future version can add
	// a lightweight WebSocket eval. The agent-browser and browser-use
	// paths handle the common case.
	_ = wsURL
	return "", fmt.Errorf("CDP tab found for %s but WebSocket eval not yet implemented (install agent-browser or browser-use)", domain)
}
